import { Router } from 'express';
import * as plantTypeController from '../controllers/plantType.controller.js';
import auth from '../middleware/auth.js';
import rbac from '../middleware/rbac.js';
import validate from '../middleware/validate.js';
import { createPlantTypeSchema, updatePlantTypeSchema } from '../validators/resource.validator.js';
const router = Router();
router.use(auth);
router.get('/', plantTypeController.listPlantTypes);
router.get('/:id', plantTypeController.getPlantType);
router.post('/', rbac('super_admin'), validate(createPlantTypeSchema), plantTypeController.createPlantType);
router.put('/:id', rbac('super_admin'), validate(updatePlantTypeSchema), plantTypeController.updatePlantType);
router.delete('/:id', rbac('super_admin'), plantTypeController.deletePlantType);
export default router;
